#!/usr/bin/env node
// Generates packages/push/src/trap-bindings.ts from data/traps.json. The
// generated file is the single source of truth for which trap each typed
// APNs error surfaces and where operators click in their logs to read the
// fix. Hand-editing the bindings file would silently drift from the catalog,
// so a `--check` mode fails CI on drift.
//
// Run plain: regenerate. Run with --check: verify the committed file is
// in sync (CI guard, wired into surface:check).
import { readFileSync, writeFileSync, existsSync } from "node:fs";
import { resolve } from "node:path";
import { parseArgs } from "node:util";
import { trapCatalog } from "../packages/surface-contracts/src/traps.ts";
import { buildReport, emitDiagnosticReport } from "./lib/diagnostics.mjs";

const { values } = parseArgs({
  options: {
    check: { type: "boolean", default: false },
    json: { type: "boolean", default: false },
  },
});

const TOOL = "generate-trap-bindings";
const TRAPS_PATH = resolve("data/traps.json");
const OUT_PATH = resolve("packages/push/src/trap-bindings.ts");

// CLAUDE.md is the rendered catalog operators read; the anchor format is
// GitHub's default heading slug. Keep this base URL aligned with the repo's
// homepage in package.json. If the repo moves, regen will refresh every
// docsUrl in lockstep.
const DOCS_BASE_URL =
  "https://github.com/glendonC/mobile-surfaces/blob/main/CLAUDE.md";

const raw = readFileSync(TRAPS_PATH, "utf8");
const parsed = JSON.parse(raw);
const result = trapCatalog.safeParse(parsed);
if (!result.success) {
  emitDiagnosticReport(
    buildReport(TOOL, [
      {
        id: "validate-traps",
        status: "fail",
        summary:
          "data/traps.json failed Zod validation; run pnpm traps:check for details.",
      },
    ]),
    { json: values.json },
  );
}

const bindings = [];
for (const entry of result.data.entries) {
  if (!entry.errorClasses) continue;
  for (const className of entry.errorClasses) {
    bindings.push({ className, trapId: entry.id });
  }
}
bindings.sort((a, b) => a.className.localeCompare(b.className));

// Catalog entries actually referenced by error classes; the binding file
// stays focused on the runtime-reachable subset rather than shipping the
// entire 29-entry catalog into every backend bundle.
const referencedTrapIds = new Set(bindings.map((b) => b.trapId));
const referencedEntries = result.data.entries
  .filter((e) => referencedTrapIds.has(e.id))
  .sort((a, b) => a.id.localeCompare(b.id));

const idMapLiteral = bindings
  .map(({ className, trapId }) => `  ${className}: "${trapId}",`)
  .join("\n");

const trapBindingsLiteral = referencedEntries
  .map((entry) => {
    const docsUrl = `${DOCS_BASE_URL}#${githubAnchor(`${entry.id}: ${entry.title}`)}`;
    return `  ${entry.id}: {
    id: "${entry.id}",
    title: ${stringLit(entry.title)},
    severity: "${entry.severity}",
    summary: ${stringLit(entry.summary)},
    symptom: ${stringLit(entry.symptom)},
    fix: ${stringLit(entry.fix)},
    docsUrl: "${docsUrl}",
  },`;
  })
  .join("\n");

const out = `// Generated from data/traps.json by scripts/generate-trap-bindings.mjs.
// The catalog is the source of truth; do not edit this file by hand.
// Run pnpm surface:check (which calls --check) to verify drift; run
// node --experimental-strip-types scripts/generate-trap-bindings.mjs to
// regenerate after editing data/traps.json.

/**
 * Runtime view of a single trap catalog entry. Carries the fields a backend
 * operator needs to act on a logged error: human title, severity, the
 * symptom they're seeing, the fix, and a docsUrl pointing at the rendered
 * catalog. Other catalog fields (tags, enforcement script, since version)
 * stay out of the bundle — consult data/traps.json or the rendered CLAUDE.md
 * for the full record.
 */
export interface TrapBinding {
  readonly id: string;
  readonly title: string;
  readonly severity: "error" | "warning" | "info";
  readonly summary: string;
  readonly symptom: string;
  readonly fix: string;
  readonly docsUrl: string;
}

export const TRAP_ID_BY_ERROR_CLASS = {
${idMapLiteral}
} as const satisfies Record<string, \`MS\${string}\`>;

export type TrapBoundErrorClassName = keyof typeof TRAP_ID_BY_ERROR_CLASS;

export const TRAP_BINDINGS = {
${trapBindingsLiteral}
} as const satisfies Record<string, TrapBinding>;

export type BoundTrapId = keyof typeof TRAP_BINDINGS;

/**
 * Look up the trap id for a given error class name. Returns undefined for
 * classes that have no catalog entry (most SDK-self-correctness errors).
 */
export function trapIdForErrorClass(className: string): string | undefined {
  return (TRAP_ID_BY_ERROR_CLASS as Record<string, string>)[className];
}

/**
 * Look up a trap binding by id. Returns undefined when the id is not in the
 * runtime subset (the binding file only ships entries reachable through a
 * typed error class).
 */
export function findTrap(trapId: string): TrapBinding | undefined {
  return (TRAP_BINDINGS as Record<string, TrapBinding>)[trapId];
}

/**
 * Look up the trap binding for an error class name. Composes
 * trapIdForErrorClass with findTrap so log aggregators can stamp a single
 * \`docsUrl\` per error without juggling two maps.
 */
export function findTrapByErrorClass(className: string): TrapBinding | undefined {
  const id = trapIdForErrorClass(className);
  return id ? findTrap(id) : undefined;
}

/**
 * Resolve the docs URL for an error class, or undefined when the class has
 * no catalog binding. Equivalent to findTrapByErrorClass(name)?.docsUrl;
 * exposed as a getter so the hot path on ApnsError can skip the object spread.
 */
export function docsUrlForErrorClass(className: string): string | undefined {
  return findTrapByErrorClass(className)?.docsUrl;
}
`;

if (values.check) {
  const current = existsSync(OUT_PATH) ? readFileSync(OUT_PATH, "utf8") : "";
  const inSync = current === out;
  emitDiagnosticReport(
    buildReport(TOOL, [
      {
        id: "trap-bindings-sync",
        status: inSync ? "ok" : "fail",
        summary: inSync
          ? "Trap bindings are in sync with data/traps.json."
          : "packages/push/src/trap-bindings.ts is out of sync with data/traps.json.",
        ...(inSync
          ? {}
          : {
              detail: {
                message:
                  "Run: node --experimental-strip-types scripts/generate-trap-bindings.mjs",
              },
            }),
      },
    ]),
    { json: values.json },
  );
} else {
  writeFileSync(OUT_PATH, out);
  if (values.json) {
    emitDiagnosticReport(
      buildReport(TOOL, [
        {
          id: "trap-bindings-write",
          status: "ok",
          summary: "Wrote packages/push/src/trap-bindings.ts.",
        },
      ]),
      { json: true },
    );
  } else {
    console.log("Wrote packages/push/src/trap-bindings.ts.");
  }
}

// Mirror the CLAUDE.md TOC slug algorithm in scripts/build-agents-md.mjs so
// every docsUrl points at a real heading the renderer emits. Lowercase the
// heading, replace any run of non-alphanumeric chars (including underscores,
// dots, colons, hyphens) with a single hyphen, then trim leading/trailing.
function githubAnchor(heading) {
  return heading
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/(^-|-$)/g, "");
}

// Emit a JSON-encoded string literal so embedded quotes and backslashes do
// not break the generated TypeScript source.
function stringLit(s) {
  return JSON.stringify(s);
}
